async (page) => {
  await page.waitForTimeout(8000);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  const hp = parsed.player_stats?.hp;
  const maxHp = parsed.player_stats?.max_hp;
  const target = parsed.current_target;
  const chat = parsed.ui_state?.recent_chat;
  const inv = parsed.inventory;

  // Auto-heal if HP < 50%
  if (hp < maxHp * 0.5) {
    const edible = inv?.find(i => i.edible);
    if (edible) {
      await page.evaluate((slot) => window.game.menu.getInventory().selectEdible(slot), edible.slot);
      await page.waitForTimeout(500);
    }
  }

  const state2 = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const p2 = JSON.parse(state2);
  return JSON.stringify({ pos: p2.player_position, hp: p2.player_stats?.hp + '/' + p2.player_stats?.max_hp, target: p2.current_target, chat: p2.ui_state?.recent_chat?.slice(-2), edibles: p2.inventory?.filter(i=>i.edible).length });
}

